let run n =
  let args_list = [|((true, true, true, true, true, true, true, true, true, true), (true, true))|] in
  let k = Array.length args_list - 1 in
  for i = 0 to n - 1 do
    ignore (main_step (args_list.(min i k)))
  done;;
  

